Context:
Browser tool definition pattern — see `platform/mcp-server/src/browser-tools/focus-tab.ts`:
```typescript
import { z } from 'zod';
import { dispatchToExtension } from '../extension-protocol.js';
import { defineBrowserTool } from './definition.js';

const focusTab = defineBrowserTool({
  name: 'browser_focus_tab',
  description: '...',
  summary: 'Focus a browser tab',
  icon: 'eye',
  group: 'Tabs',
  input: z.object({
    tabId: z.number().int().positive().describe('Tab ID to focus'),
  }),
  handler: async (args, state) => dispatchToExtension(state, 'browser.focusTab', { tabId: args.tabId }),
});

export { focusTab };
```

For show-notification.ts:
```typescript
import { z } from 'zod';
import { dispatchToExtension } from '../extension-protocol.js';
import { defineBrowserTool } from './definition.js';

const showNotification = defineBrowserTool({
  name: 'browser_notify',
  description: 'Show a Chrome desktop notification. Use this to alert the user about completed tasks, errors, or important events. ' +
    'The notification appears even when Chrome is in the background. ' +
    'If url is provided, clicking the notification opens that URL in a new tab; otherwise it opens the OpenTabs side panel.',
  summary: 'Show a desktop notification',
  icon: 'bell',
  group: 'Notifications',
  input: z.object({
    title: z.string().describe('Notification title'),
    message: z.string().describe('Notification body text'),
    iconUrl: z.string().url().optional().describe('Optional icon URL (defaults to the OpenTabs extension icon)'),
    requireInteraction: z.boolean().optional().describe('If true, the notification stays visible until the user clicks or dismisses it (default: false)'),
    contextMessage: z.string().optional().describe('Optional secondary text shown below the main message'),
    url: z.string().url().optional().describe('Optional URL to open when the notification is clicked'),
  }),
  handler: async (args, state) => dispatchToExtension(state, 'browser.showNotification', args),
});

export { showNotification };
```

In browser-tools/index.ts, add:
1. Import: `import { showNotification } from './show-notification.js';`
